// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_middleware_errors_architecture_2(trusted: boolean, parsed: boolean, authorized: boolean, headersSent: boolean): { stage: string; status: number; delegate: boolean } {
  if (headersSent) return { stage: "error-delegate", status: 500, delegate: true };
  if (!trusted) return { stage: "trust", status: 400, delegate: false };
  if (!parsed) return { stage: "parse", status: 422, delegate: false };
  if (!authorized) return { stage: "authorize", status: 403, delegate: false };
  return { stage: "handler", status: 204, delegate: false };
}

